/**
 * Concept Editor Layout Configuration
 */
(function() {
	'use strict';
	
	angular.module('app.concept').directive('conceptLayout', conceptLayout);
	
	conceptLayout.$inject = ['$timeout', '$window'];
	
	function conceptLayout($timeout, $window) {
		var directive = {
				restrict: 'EA',
				transclude: true,
				template: '<p ng-hide></p>',
				controller: 'ConceptController',
				link: link
			};
		return directive;
		
		function link(scope, element, attributes, controller, transclude) {
			transclude(
				function injectLinkedClone(clone) {
					element.append(clone);
				}
			);

			element.layout({
				center__paneSelector: ".outer-center", //
				//east__paneSelector:   ".outer-east",	 //
				west__paneSelector:   ".outer-west",	 //
				south__paneSelector: ".outer-south",
				//east__size: "25%",
				west__size: "25%",
				//south__size: "3%",
				fxName:	"none",		// none, slide, drop, scale
				/**
				center__childOptions:
				{
					center__paneSelector: ".outer-center-center",	// Workspace(Editor)
					south__paneSelector:   ".outer-center-south",	  // Member List
					south__size: "75%",
					fxName:	"none"		// none, slide, drop, scale
				},
				
				east__childOptions:
				{
					center__paneSelector: ".outer-east-center",	// 
					south__paneSelector:  ".outer-east-south",	// 
					//south__initHidden: false
					south__size: "55%"
				}*/
			});
			
			var w = angular.element($window);
	        w.bind('resize', resize);
	        w.trigger('resize');
	        
	        function resize($event) {
	        	var target = $event.target,
	        	innerHeight = target.innerHeight;
	        	// layout height 변경
	        	element.css('height', innerHeight - 60 + 'px');
	        };
	         
	        $timeout(function(){
	        	//console.log('/////'+element.find('md-tab-item > span').length);md-tab-content
		       element.find('md-tabs-canvas').css('height', '50px');
		       element.find('md-pagination-wrapper').css('height', '50px');
		       element.find('md-tab-item').css('padding-top', '15px').css('padding-bottom', '15px');
		       element.find('md-tab-content').css('margin-top', '15px');
	        });
	        
		}
	}
	
	angular.module('app.concept').directive('ceLoading', ceLoading);
	
	ceLoading.$inject = ['$timeout'];
	
	function ceLoading($timeout) {
		var directive = {
				restrict: 'EA',
				template: '<div class="ce-loading" ng-show="loading"></div>'+
							'<img ng-show="loading" src="data:image/gif;base64," '+
							' style="position:absolute;"/>',
				scope: {
					loading : '=loading'
				},
				//replace : true,
				link: link
			};
		return directive;
		function link(scope, element, attributes, controller, transclude) {
			scope.$watch('loading', function(nv, ov){
				
				var parent = angular.element(attributes.target);
				var offset = attributes.offset === 'false' ? {top:0,left:parent.position().left} : parent.position();
				var width = parent.width(), height = parent.height();
				element.children('div').css({
					'left' : '0px',
					'top' : offset.top+'px',
					'width' : width+'px',
					'height' : height+'px'
				});
				var imgTop = offset.top + ((height / 2) >= 200 ? 150 : (height / 2)) - 15, imgLeft = offset.left + (width/2) - 15;
				element.children('img').css({
					top : imgTop + 'px',
					left : ((width/2) - 15)+'px'
				});
				
				
			});
		}
	}
})();